# solution.py
"""Office_Task_Collaborator -- a collaborative task management system.

This module implements ``TeamCollaborationManager``: a centralized, thread-safe,
in-memory platform that lets office teams create projects and tasks, assign work,
track status and deadlines, communicate through messages, monitor individual and
team performance, generate reports, and synchronize deadlines with calendar
applications (Google Calendar / Outlook via iCalendar).

Design highlights
-----------------
* Pure Python standard library, ASCII only -- no third party dependencies.
* A single shared re-entrant lock guards every mutation, so the manager and all
  of its sub-stores are safe to use from many threads at once.
* Identifiers are globally unique across every entity type and start at 1.
* Every accessor returns deep copies, so callers can never mutate internal state
  by holding on to a returned object.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime, timedelta
from enum import Enum
from typing import Callable, Dict, List, Optional, Sequence, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Roles a user can hold within the system."""

    MEMBER = "member"
    ADMIN = "admin"


class Priority(Enum):
    """Relative importance of a task."""

    LOW = "low"
    MEDIUM = "medium"
    HIGH = "high"
    URGENT = "urgent"


class ReportFormat(Enum):
    """Supported export formats for a generated report."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """The kind of report produced by the manager."""

    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


class CalendarProvider(Enum):
    """Calendar back-ends that task deadlines can be synchronized with."""

    GOOGLE = "google"
    OUTLOOK = "outlook"
    ICAL = "ical"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the system."""


class ValidationError(TeamCollaborationError):
    """Raised when supplied input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with the current state."""


# ---------------------------------------------------------------------------
# Domain entities
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A team member."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A project that groups tasks together."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    """A unit of work tracked by the system."""

    id: int
    project_id: int
    title: str
    description: str
    status: TaskStatus
    assignee_id: Optional[int]
    priority: Priority
    deadline: Optional[datetime]
    created_at: datetime
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None


@dataclass
class Message:
    """A message posted to a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    created_at: datetime
    attachments: List[Attachment] = field(default_factory=list)
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """Peer feedback about a team member's performance."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


@dataclass
class CalendarEvent:
    """A calendar event derived from a task deadline."""

    uid: str
    title: str
    start: datetime
    end: datetime
    description: str
    provider: CalendarProvider


# ---------------------------------------------------------------------------
# Sub-stores
#
# The stores intentionally stay thin: they own the data structures for one slice
# of the domain and share the manager's lock so that every store participates in
# the same critical sections.  Business logic lives on the manager.
# ---------------------------------------------------------------------------
class _BaseStore:
    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock


class _UserStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._items: Dict[int, User] = {}
        self._by_username: Dict[str, int] = {}
        self._by_email: Dict[str, int] = {}


class _ProjectStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._items: Dict[int, Project] = {}


class _TaskStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._items: Dict[int, Task] = {}
        self._by_assignee: Dict[int, set] = {}


class _MessageStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._items: Dict[int, Message] = {}


class _PerformanceStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._ratings: Dict[int, List[Rating]] = {}


class _ReportStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)


class _CalendarStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._synced: Dict[int, CalendarEvent] = {}


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Central coordinator for users, projects, tasks, messaging and reports."""

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._lock = threading.RLock()
        self._now: Callable[[], datetime] = now if now is not None else (lambda: datetime.now())
        self._seq = 0

        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)
        self.calendar = _CalendarStore(self._lock)

    # -- internal helpers ---------------------------------------------------
    def _next_id(self) -> int:
        self._seq += 1
        return self._seq

    @staticmethod
    def _copy(obj):
        return copy.deepcopy(obj)

    @staticmethod
    def _require_text(value, label) -> str:
        if not isinstance(value, str) or not value.strip():
            raise ValidationError("{0} is required".format(label))
        return value.strip()

    @staticmethod
    def _validate_email(email) -> str:
        if not isinstance(email, str):
            raise ValidationError("email must be a string")
        cleaned = email.strip()
        if not cleaned or "@" not in cleaned:
            raise ValidationError("a valid email address is required")
        return cleaned

    @staticmethod
    def _validate_datetime(value, label) -> datetime:
        if not isinstance(value, datetime):
            raise ValidationError("{0} must be a datetime".format(label))
        return value

    def _require_user(self, user_id) -> User:
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id) -> Project:
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id) -> Task:
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id) -> Message:
        message = self.messages._items.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    def _tasks_for_assignee(self, user_id) -> List[Task]:
        ids = self.tasks._by_assignee.get(user_id, set())
        return [self.tasks._items[i] for i in ids if i in self.tasks._items]

    def _set_assignee(self, task: Task, new_assignee_id: Optional[int]) -> None:
        old = task.assignee_id
        if old == new_assignee_id:
            return
        if old is not None:
            bucket = self.tasks._by_assignee.get(old)
            if bucket is not None:
                bucket.discard(task.id)
                if not bucket:
                    del self.tasks._by_assignee[old]
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self.tasks._by_assignee.setdefault(new_assignee_id, set()).add(task.id)

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role: UserRole = UserRole.MEMBER) -> User:
        with self._lock:
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            clean_username = self._require_text(username, "username")
            clean_email = self._validate_email(email)
            if clean_username in self.users._by_username:
                raise DuplicateError("username '{0}' already exists".format(clean_username))
            if clean_email in self.users._by_email:
                raise DuplicateError("email '{0}' already exists".format(clean_email))
            user_id = self._next_id()
            user = User(
                id=user_id,
                username=clean_username,
                email=clean_email,
                role=role,
                created_at=self._now(),
            )
            self.users._items[user_id] = user
            self.users._by_username[clean_username] = user_id
            self.users._by_email[clean_email] = user_id
            return self._copy(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return self._copy(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            ordered = sorted(self.users._items.values(), key=lambda u: u.id)
            return [self._copy(u) for u in ordered]

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._require_user(user_id)

            new_username = None
            if username is not None:
                new_username = self._require_text(username, "username")
                owner = self.users._by_username.get(new_username)
                if owner is not None and owner != user_id:
                    raise DuplicateError("username '{0}' already exists".format(new_username))

            new_email = None
            if email is not None:
                new_email = self._validate_email(email)
                owner = self.users._by_email.get(new_email)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email '{0}' already exists".format(new_email))

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if new_username is not None and new_username != user.username:
                del self.users._by_username[user.username]
                self.users._by_username[new_username] = user_id
                user.username = new_username
            if new_email is not None and new_email != user.email:
                del self.users._by_email[user.email]
                self.users._by_email[new_email] = user_id
                user.email = new_email
            if role is not None:
                user.role = role

            return self._copy(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            user = self._require_user(user_id)
            for project in self.projects._items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns project {0}".format(project.id))
            for task in self.tasks._items.values():
                if task.assignee_id == user_id and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open task {0}".format(task.id))

            del self.users._items[user_id]
            self.users._by_username.pop(user.username, None)
            self.users._by_email.pop(user.email, None)
            self.tasks._by_assignee.pop(user_id, None)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description="") -> Project:
        with self._lock:
            self._require_user(owner_id)
            clean_name = self._require_text(name, "project name")
            self._validate_datetime(start_date, "start_date")
            self._validate_datetime(end_date, "end_date")
            if end_date < start_date:
                raise ValidationError("end_date cannot be before start_date")
            project_id = self._next_id()
            project = Project(
                id=project_id,
                name=clean_name,
                description=description if isinstance(description, str) else "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self.projects._items[project_id] = project
            return self._copy(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return self._copy(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            ordered = sorted(self.projects._items.values(), key=lambda p: p.id)
            return [self._copy(p) for p in ordered]

    def update_project(self, project_id, name=None, description=None,
                       start_date=None, end_date=None) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            new_name = project.name
            if name is not None:
                new_name = self._require_text(name, "project name")

            new_start = project.start_date
            if start_date is not None:
                new_start = self._validate_datetime(start_date, "start_date")
            new_end = project.end_date
            if end_date is not None:
                new_end = self._validate_datetime(end_date, "end_date")
            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")

            project.name = new_name
            if description is not None:
                project.description = description
            project.start_date = new_start
            project.end_date = new_end
            return self._copy(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            self._require_project(project_id)
            task_ids = [t.id for t in self.tasks._items.values() if t.project_id == project_id]
            for task_id in task_ids:
                self._delete_task_internal(task_id)
            message_ids = [m.id for m in self.messages._items.values()
                           if m.project_id == project_id]
            for message_id in message_ids:
                self.messages._items.pop(message_id, None)
            del self.projects._items[project_id]

    def _delete_task_internal(self, task_id) -> None:
        task = self.tasks._items.pop(task_id, None)
        if task is None:
            return
        if task.assignee_id is not None:
            bucket = self.tasks._by_assignee.get(task.assignee_id)
            if bucket is not None:
                bucket.discard(task_id)
                if not bucket:
                    del self.tasks._by_assignee[task.assignee_id]
        message_ids = [m.id for m in self.messages._items.values() if m.task_id == task_id]
        for message_id in message_ids:
            self.messages._items.pop(message_id, None)

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None,
                    description="", priority: Priority = Priority.MEDIUM) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            clean_title = self._require_text(title, "task title")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if not isinstance(priority, Priority):
                raise ValidationError("priority must be a Priority")
            if deadline is not None:
                self._validate_datetime(deadline, "deadline")
                if deadline < project.start_date:
                    raise ValidationError("deadline cannot be before the project start")

            task_id = self._next_id()
            task = Task(
                id=task_id,
                project_id=project_id,
                title=clean_title,
                description=description if isinstance(description, str) else "",
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                priority=priority,
                deadline=deadline,
                created_at=self._now(),
            )
            self.tasks._items[task_id] = task
            if assignee_id is not None:
                self.tasks._by_assignee.setdefault(assignee_id, set()).add(task_id)
            return self._copy(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return self._copy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            tasks = [t for t in self.tasks._items.values() if t.project_id == project_id]
            tasks.sort(key=lambda t: t.id)
            return [self._copy(t) for t in tasks]

    def list_tasks_by_assignee(self, assignee_id) -> List[Task]:
        with self._lock:
            self._require_user(assignee_id)
            tasks = self._tasks_for_assignee(assignee_id)
            tasks.sort(key=lambda t: t.id)
            return [self._copy(t) for t in tasks]

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return self._copy(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return self._copy(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return self._copy(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                self._validate_datetime(deadline, "deadline")
                project = self._require_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline cannot be before the project start")
            task.deadline = deadline
            return self._copy(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            task = self._require_task(task_id)
            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            task.status = status
            return self._copy(task)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments: Optional[Sequence[Tuple[str, bytes]]] = None) -> Message:
        with self._lock:
            self._require_user(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError("exactly one of project_id or task_id is required")
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            text = body if isinstance(body, str) else ""
            attachment_objs = self._build_attachments(attachments, author_id)
            if not text.strip() and not attachment_objs:
                raise ValidationError("a message must have a body or an attachment")

            message_id = self._next_id()
            message = Message(
                id=message_id,
                author_id=author_id,
                body=text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                created_at=self._now(),
                attachments=attachment_objs,
            )
            self.messages._items[message_id] = message
            return self._copy(message)

    def _build_attachments(self, attachments, author_id) -> List[Attachment]:
        result: List[Attachment] = []
        if not attachments:
            return result
        now = self._now()
        for item in attachments:
            filename, data = item
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("attachment filename is required")
            size = len(data) if data is not None else 0
            result.append(
                Attachment(
                    filename=filename,
                    size=size,
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
            )
        return result

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            if not isinstance(new_body, str) or not new_body.strip():
                raise ValidationError("message body cannot be empty")
            message.body = new_body
            message.edited_at = self._now()
            return self._copy(message)

    def add_attachment(self, message_id, user_id, filename, data) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may attach to this message")
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("attachment filename is required")
            attachment = Attachment(
                filename=filename,
                size=len(data) if data is not None else 0,
                uploaded_by=user_id,
                uploaded_at=self._now(),
            )
            message.attachments.append(attachment)
            return self._copy(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            messages = [m for m in self.messages._items.values() if m.project_id == project_id]
            messages.sort(key=lambda m: m.id)
            return [self._copy(m) for m in messages]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            messages = [m for m in self.messages._items.values() if m.task_id == task_id]
            messages.sort(key=lambda m: m.id)
            return [self._copy(m) for m in messages]

    def delete_message(self, message_id, user_id) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may delete this message")
            self.messages._items.pop(message_id, None)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            durations = self._completion_durations(self._tasks_for_assignee(user_id))
            if not durations:
                return None
            return sum(durations) / len(durations)

    @staticmethod
    def _completion_durations(tasks) -> List[float]:
        durations = []
        for task in tasks:
            if (task.status == TaskStatus.COMPLETED
                    and task.started_at is not None
                    and task.completed_at is not None):
                durations.append((task.completed_at - task.started_at).total_seconds())
        return durations

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if task_id is not None:
                self._require_task(task_id)
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if isinstance(score, bool) or not isinstance(score, int) or not (1 <= score <= 5):
                raise ValidationError("score must be an integer between 1 and 5")

            rating_id = self._next_id()
            rating = Rating(
                id=rating_id,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback if isinstance(feedback, str) else "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance._ratings.setdefault(ratee_id, []).append(rating)
            return self._copy(rating)

    def get_ratings_summary(self, user_id) -> Dict:
        with self._lock:
            self._require_user(user_id)
            ratings = self.performance._ratings.get(user_id, [])
            count = len(ratings)
            average = (sum(r.score for r in ratings) / count) if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [self._copy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> Dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            completion_rate = (completed / total) if total else 0.0
            durations = self._completion_durations(tasks)
            average_completion_time = (sum(durations) / len(durations)) if durations else None

            ratings = self.performance._ratings.get(user_id, [])
            rating_count = len(ratings)
            rating_average = (sum(r.score for r in ratings) / rating_count) if rating_count else 0.0

            upcoming = self._upcoming_deadlines(tasks, self._now())

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": average_completion_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
                "upcoming_deadlines": upcoming,
            }

    @staticmethod
    def _upcoming_deadlines(tasks, now, within_days=7):
        horizon = now + timedelta(days=within_days)
        upcoming = [
            t for t in tasks
            if t.deadline is not None
            and t.status != TaskStatus.COMPLETED
            and now <= t.deadline <= horizon
        ]
        upcoming.sort(key=lambda t: (t.deadline, t.id))
        return [copy.deepcopy(t) for t in upcoming]

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id) -> Dict:
        with self._lock:
            self._require_project(project_id)
            now = self._now()
            tasks = [t for t in self.tasks._items.values() if t.project_id == project_id]
            total = len(tasks)

            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = (completed / total) if total else 0.0

            overdue = sum(
                1 for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )

            per_assignee: Dict[int, Dict] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id,
                    {"user_id": task.assignee_id, "total": 0, "completed": 0},
                )
                bucket["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> Dict:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                scoped_tasks = [t for t in self.tasks._items.values()
                                if t.project_id == project_id]
            else:
                scoped_tasks = list(self.tasks._items.values())

            user_ids = sorted({t.assignee_id for t in scoped_tasks if t.assignee_id is not None})
            columns = [
                "user_id",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]

            rows = []
            for user_id in user_ids:
                user_tasks = [t for t in scoped_tasks if t.assignee_id == user_id]
                total = len(user_tasks)
                completed = sum(1 for t in user_tasks if t.status == TaskStatus.COMPLETED)
                completion_rate = (completed / total) if total else 0.0
                durations = self._completion_durations(user_tasks)
                average_completion_time = (sum(durations) / len(durations)) if durations else None
                ratings = self.performance._ratings.get(user_id, [])
                rating_count = len(ratings)
                rating_average = (
                    (sum(r.score for r in ratings) / rating_count) if rating_count else 0.0
                )
                rows.append({
                    "user_id": user_id,
                    "total_tasks": total,
                    "completed_tasks": completed,
                    "completion_rate": completion_rate,
                    "average_completion_time": average_completion_time,
                    "rating_count": rating_count,
                    "rating_average": rating_average,
                })

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "scope_project_id": project_id,
                "columns": columns,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> Dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            tasks.sort(key=lambda t: t.id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
