    def export_report(self, report, report_format):
        with self._lock:
            if not isinstance(report_format, ReportFormat):
                raise ValidationError("report_format must be a ReportFormat")
            if not isinstance(report, dict):
                raise ValidationError("report must be a mapping produced by this manager")
            table = self._report_to_table(report)
            if report_format == ReportFormat.CSV:
                return self._table_to_csv(table)
            return self._table_to_pdf(table)

    def _report_to_table(self, report) -> List[List[str]]:
        rows = report.get("rows")
        if isinstance(rows, list):
            columns = report.get("columns")
            if not columns:
                columns = list(rows[0].keys()) if rows and isinstance(rows[0], dict) else ["value"]
            table = [[str(c) for c in columns]]
            for row in rows:
                if isinstance(row, dict):
                    table.append([self._cell(row.get(c, "")) for c in columns])
                else:
                    table.append([self._cell(row)])
            return table

        tasks = report.get("tasks")
        if isinstance(tasks, list) and tasks and isinstance(tasks[0], dict):
            columns = report.get("columns") or list(tasks[0].keys())
            table = [[str(c) for c in columns]]
            for row in tasks:
                table.append([self._cell(row.get(c, "")) for c in columns])
            return table

        table = [["metric", "value"]]
        for key, value in report.items():
            table.append([str(key), self._cell(value)])
        return table

    @staticmethod
    def _cell(value) -> str:
        if value is None:
            return ""
        if isinstance(value, Enum):
            return str(value.value)
        if isinstance(value, datetime):
            return value.isoformat()
        if isinstance(value, float):
            return repr(value)
        return str(value)

    @staticmethod
    def _table_to_csv(table) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        for row in table:
            writer.writerow(row)
        return buffer.getvalue()

    def _table_to_pdf(self, table) -> bytes:
        lines = [" | ".join(row) for row in table]
        return self._build_pdf(lines)

    @staticmethod
    def _build_pdf(lines) -> bytes:
        def escape(text: str) -> str:
            return text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")

        if not lines:
            lines = [""]

        content_parts = ["BT", "/F1 12 Tf", "14 TL", "50 750 Td"]
        for index, line in enumerate(lines):
            safe = "".join(ch if 32 <= ord(ch) < 127 else "?" for ch in line)
            if index > 0:
                content_parts.append("T*")
            content_parts.append("({0}) Tj".format(escape(safe)))
        content_parts.append("ET")
        content = "\n".join(content_parts).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
             b"/Resources << /Font << /F1 4 0 R >> >> /Contents 5 0 R >>"),
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
            (b"<< /Length " + str(len(content)).encode("ascii") + b" >>\nstream\n"
             + content + b"\nendstream"),
        ]

        pdf = bytearray(b"%PDF-1.4\n")
        offsets = []
        for number, obj in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += str(number).encode("ascii") + b" 0 obj\n" + obj + b"\nendobj\n"

        xref_position = len(pdf)
        size = len(objects) + 1
        pdf += b"xref\n"
        pdf += b"0 " + str(size).encode("ascii") + b"\n"
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        pdf += b"trailer\n"
        pdf += b"<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
        pdf += b"startxref\n"
        pdf += str(xref_position).encode("ascii") + b"\n"
        pdf += b"%%EOF"
        return bytes(pdf)

    # ------------------------------------------------------------------
    # Calendar integration
    # ------------------------------------------------------------------
    def sync_task_deadline(self, task_id, provider: CalendarProvider = CalendarProvider.ICAL,
                           duration_minutes: int = 60) -> CalendarEvent:
        with self._lock:
            if not isinstance(provider, CalendarProvider):
                raise ValidationError("provider must be a CalendarProvider")
            task = self._require_task(task_id)
            if task.deadline is None:
                raise ValidationError("task has no deadline to synchronize")
            start = task.deadline
            end = task.deadline + timedelta(minutes=duration_minutes)
            event = CalendarEvent(
                uid="task-{0}@office-collab".format(task_id),
                title=task.title,
                start=start,
                end=end,
                description=task.description,
                provider=provider,
            )
            self.calendar._synced[task_id] = event
            return self._copy(event)

    def get_upcoming_deadlines(self, user_id, within_days: int = 7) -> List[Task]:
        with self._lock:
            self._require_user(user_id)
            return self._upcoming_deadlines(
                self._tasks_for_assignee(user_id), self._now(), within_days
            )

    def export_calendar(self, project_id=None,
                        provider: CalendarProvider = CalendarProvider.ICAL) -> str:
        with self._lock:
            if not isinstance(provider, CalendarProvider):
                raise ValidationError("provider must be a CalendarProvider")
            if project_id is not None:
                self._require_project(project_id)
                tasks = [t for t in self.tasks._items.values()
                         if t.project_id == project_id and t.deadline is not None]
            else:
                tasks = [t for t in self.tasks._items.values() if t.deadline is not None]
            tasks.sort(key=lambda t: t.id)
            return self._build_ics(tasks, provider)

    def _build_ics(self, tasks, provider: CalendarProvider) -> str:
        def fmt(value: datetime) -> str:
            return value.strftime("%Y%m%dT%H%M%S")

        stamp = fmt(self._now())
        lines = [
            "BEGIN:VCALENDAR",
            "VERSION:2.0",
            "PRODID:-//Office Task Collaborator//{0}//EN".format(provider.value.upper()),
            "CALSCALE:GREGORIAN",
        ]
        for task in tasks:
            lines.extend([
                "BEGIN:VEVENT",
                "UID:task-{0}@office-collab".format(task.id),
                "DTSTAMP:{0}".format(stamp),
                "DTSTART:{0}".format(fmt(task.deadline)),
                "DTEND:{0}".format(fmt(task.deadline + timedelta(hours=1))),
                "SUMMARY:{0}".format(task.title),
                "DESCRIPTION:{0}".format(task.description or ""),
                "END:VEVENT",
            ])
        lines.append("END:VCALENDAR")
        return "\r\n".join(lines) + "\r\n"


